SELECT package_name, package_version
FROM service_packages
WHERE package_type = 'Go V1';

SELECT note
FROM service_notes
WHERE service_id = 1;

SELECT COUNT(package_id) AS package_count
FROM service_packages
WHERE service_id = 1;

SELECT COUNT(DISTINCT package_name) AS unique_package_count
  FROM service_packages
  WHERE service_id = 1;
